def categorize_marriage(man_rank: int, woman_rank: int) -> str:
    if man_rank == woman_rank:
        return "Same-caste marriage"
    elif man_rank > woman_rank:
        return "Anuloma marriage (going with the grain)"
    else:
        return "Pratiloma marriage (going against the grain)"

# Example usage:
print(categorize_marriage(5, 3))  # Output: 'Anuloma marriage (going with the grain)'
print(categorize_marriage(2, 4))  # Output: 'Pratiloma marriage (going against the grain)'
print(categorize_marriage(3, 3))  # Output: 'Same-caste marriage'
